#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
int n,c,s,ac,as;
char a[1005][1005];
int b[1005][1005];
bool ju[1005][1005]={false};
vector<int> ss,cc;
void d(int x,int y)
{
	if(a[x-1][y]=='#') b[x][y]++;
	if(a[x+1][y]=='#') b[x][y]++;
	if(a[x][y+1]=='#') b[x][y]++;
	if(a[x][y-1]=='#') b[x][y]++;	
}
void dfs(int x,int y)
{
	if(ju[x][y]==false||x<1||x>n||y<1||y>n) return;
	ju[x][y]=false;
	s++;
	c+=4-b[x][y];
	dfs(x-1,y);
	dfs(x+1,y);
	dfs(x,y+1);
	dfs(x,y-1);			
}
signed main(void)
{
	cin>>n;
	FOR(i,1,n)
	    FOR(j,1,n)
	    {
	    	cin>>a[i][j];
	    	if(a[i][j]=='#') ju[i][j]=true;
	    }
	FOR(i,1,n)
	    FOR(j,1,n) if(a[i][j]=='#') d(i,j); 
	FOR(i,1,n)
	    FOR(j,1,n)
		{
			if(ju[i][j]==true)
			{
				dfs(i,j);
				ss.pb(s);
				s=0;
				cc.pb(c);
				c=0; 
			}
	    }
	ac=cc[0];as=ss[0];
	FOR(i,1,cc.size()-1)
	{
		if(ss[i]>as)
		{
			as=ss[i];
			ac=cc[i];
		}
		if(ss[i]==as&&cc[i]<ac) ac=cc[i];
	}
	cout<<as<<" "<<ac<<endl;
	return false;
}
